import re

# Mapping dictionary
word_to_num = {
    "one": 1,
    "two": 2,
    "three": 3,
    "four": 4,
    "five": 5,
    "six": 6,
    "seven": 7,
    "eight": 8,
    "nine": 9,
    "ten": 10,
}

def convert_values(data: str) -> str:
    """
    Takes a string like SQL value tuples and replaces quoted number words
    with their integer representation.
    """
    # Regex to find things inside quotes
    def replacer(match):
        word = match.group(1).lower()
        if word in word_to_num:
            return str(word_to_num[word])   # return number w/o quotes
        return f"'{word}'"  # keep original quotes if not a number word

    # Replace any 'word' with mapped integer
    return re.sub(r"'([^']+)'", replacer, data)

